document.getElementById("continue-game").onclick=()=>{enterCasino();updateHUD();};
document.getElementById("start-new-casino").onclick=startNewCasino;
if(saveExists){document.getElementById("intro").classList.add("done");document.getElementById("start-menu").classList.remove("done");}
else document.getElementById("start-menu").classList.add("done");

function ensureAudio(){if(!audioContext)audioContext=new(window.AudioContext||window.webkitAudioContext)();if(audioContext.state==="suspended")audioContext.resume();if(!musicTimer)startMusic();}
function tone(freq,duration=.12,type="sine",volume=.08){if(!audioContext||!state.sfx)return;const o=audioContext.createOscillator(),g=audioContext.createGain();o.frequency.value=freq;o.type=type;g.gain.setValueAtTime(volume*state.sfx/100,audioContext.currentTime);g.gain.exponentialRampToValueAtTime(.001,audioContext.currentTime+duration);o.connect(g).connect(audioContext.destination);o.start();o.stop(audioContext.currentTime+duration);}
function startMusic(){const melody=[220,261.6,329.6,392,329.6,293.7,261.6,196];let i=0;musicTimer=setInterval(()=>{if(!audioContext||!state.music)return;const o=audioContext.createOscillator(),g=audioContext.createGain();o.type="triangle";o.frequency.value=melody[i++%melody.length];g.gain.setValueAtTime(.018*state.music/100,audioContext.currentTime);g.gain.exponentialRampToValueAtTime(.001,audioContext.currentTime+.9);o.connect(g).connect(audioContext.destination);o.start();o.stop(audioContext.currentTime+1);},800);}
document.getElementById("sound-toggle").onclick=()=>{ensureAudio();state.music=state.music?0:20;document.getElementById("sound-toggle").textContent=state.music?"🔊":"🔇";saveState();};
document.getElementById("new-game-button").onclick=startNewCasino;
document.addEventListener("pointerdown",ensureAudio,{once:true});

