const machineNames=["MEOW MIX","PAW PAYOUT","TUNA TUMBLER","FURTUNE 500","CATNIP CASH","WHISKER WIN","MOONLIGHT 7S","SARDINE SPIN","VELVET JACKPOT","PURR-A-DICE"];
const machineSpaces=[];
const STAND_RADIUS=18;
const GRID={x:100,y:190,t:40,cols:40,rows:24};
const TILE={floor:"floor",wall:"wall",door:"door",furniture:"furniture",machine:"machine",counter:"counter",staff:"staff-only",exit:"exit"};
const tileMap=new Map();
const key=(c,r)=>`${c},${r}`;
function tileRect(c,r,w=1,h=1){return {x:GRID.x+c*GRID.t,y:GRID.y+r*GRID.t,w:w*GRID.t,h:h*GRID.t};}
function tileCenter(c,r){return {x:GRID.x+c*GRID.t+GRID.t/2,y:GRID.y+r*GRID.t+GRID.t/2};}
function setTile(c,r,type){if(c>=0&&c<GRID.cols&&r>=0&&r<GRID.rows)tileMap.set(key(c,r),type);}
function fillTiles(c,r,w,h,type){for(let y=r;y<r+h;y++)for(let x=c;x<c+w;x++)setTile(x,y,type);}
function tileType(c,r){return tileMap.get(key(c,r))||TILE.wall;}
function isPublicWalkable(type){return type===TILE.floor||type===TILE.door||type===TILE.exit;}
function canUseTile(type,opts={}){return isPublicWalkable(type)||(type===TILE.staff&&(opts.allowStaff||opts.allowWorkshop));}
function buildGridLayout(){
 tileMap.clear();
 [[1,7,5,10],[7,3,17,17],[25,3,13,9],[25,13,8,8],[34,13,4,6],[1,18,13,5],[14,18,11,1]].forEach(rect=>fillTiles(...rect,TILE.floor));
 fillTiles(16,19,9,4,TILE.staff);
 [[0,11,1,3],[6,10,1,3],[24,7,1,4],[24,14,1,4],[33,15,1,2],[8,17,3,1],[18,18,3,1],[14,18,2,1]].forEach(rect=>fillTiles(...rect,TILE.door));
 fillTiles(0,11,1,3,TILE.exit);
 [[3,9,2,5],[2,8,2,2],[2,14,2,2]].forEach(rect=>fillTiles(...rect,TILE.counter));
 [[27,5,4,3],[33,5,4,3],[29,9,6,2]].forEach(rect=>fillTiles(...rect,TILE.furniture));
 [[26,15,5,2],[26,17,5,1]].forEach(rect=>fillTiles(...rect,TILE.counter));
 [[35,15,2,2],[3,20,2,2],[10,20,3,2],[6,20,3,2],[17,20,4,2],[21,21,3,1],[5,16,1,1],[22,3,1,2],[37,18,1,1]].forEach(rect=>fillTiles(...rect,TILE.furniture));
 machineSpaces.forEach(space=>{const c=Math.floor((space.x-GRID.x)/GRID.t),r=Math.floor((space.y-GRID.y)/GRID.t);fillTiles(c,r,Math.ceil(space.w/GRID.t),Math.ceil(space.h/GRID.t),TILE.machine);});
 for(let r=0;r<GRID.rows;r++)for(let c=0;c<GRID.cols;c++){if(tileMap.has(key(c,r)))continue;const near=[[1,0],[-1,0],[0,1],[0,-1]].some(([dx,dy])=>canUseTile(tileType(c+dx,r+dy),{allowStaff:true}));if(near)setTile(c,r,TILE.wall);}
}
function positionGridElement(selector,c,r,w,h){const el=document.querySelector(selector);if(!el)return;const rect=tileRect(c,r,w,h);Object.assign(el.style,{left:`${rect.x-60}px`,top:`${rect.y-110}px`,right:"auto",bottom:"auto",width:`${rect.w}px`,height:`${rect.h}px`});}
function positionGridObject(selector,c,r,w,h){const el=document.querySelector(selector);if(!el)return;const rect=tileRect(c,r,w,h),parent=el.parentElement,room=parent?.classList?.contains("room");const baseX=room?60+(parseFloat(parent.style.left)||0):60,baseY=room?110+(parseFloat(parent.style.top)||0):110;Object.assign(el.style,{left:`${rect.x-baseX}px`,top:`${rect.y-baseY}px`,right:"auto",bottom:"auto",width:`${rect.w}px`,height:`${rect.h}px`});}
function applyGridLayout(){
 positionGridElement(".cashier-room",1,7,5,10);positionGridElement(".slot-room",7,3,17,17);positionGridElement(".table-room",25,3,13,9);positionGridElement(".bar-room",25,13,8,8);
 positionGridElement(".restroom-room",34,13,4,6);positionGridElement(".lounge-room",1,18,13,5);positionGridElement(".maintenance-room",16,19,9,4);
 positionGridObject(".cashier-desk",3,9,2,5);positionGridObject(".catm-one",2,8,2,2);positionGridObject(".catm-two",2,14,2,2);
 positionGridObject(".blackjack-table",27,5,4,3);positionGridObject(".roulette-table",33,5,4,3);positionGridObject(".craps-reserve",29,9,6,2);
 positionGridObject(".bar-counter",26,15,5,2);positionGridObject(".bar-stools",26,17,5,1);positionGridObject(".restroom-door",35,15,2,2);
 positionGridObject(".chair-a",3,20,2,2);positionGridObject(".chair-b",10,20,3,2);positionGridObject(".coffee-table",6,20,3,2);positionGridObject(".shelves",17,20,4,2);positionGridObject(".workbench",21,21,3,1);
 positionGridObject(".p1",5,16,1,1);positionGridObject(".statue",22,3,1,2);positionGridObject(".p2",37,18,1,1);
 positionGridObject(".door-slots",0,11,2,1);positionGridObject(".door-games",24,7,1,2);positionGridObject(".door-blackjack",6,10,1,3);positionGridObject(".door-roulette",24,14,1,2);
 positionGridObject(".door-cashier",2,6,3,1);positionGridObject(".door-tea",27,12,3,1);positionGridObject(".door-lounge",8,17,3,1);positionGridObject(".door-workshop",18,18,3,1);positionGridObject(".door-restroom",33,15,1,2);
}
function machineLabel(index){return machineNames[(index-2)%machineNames.length]||`MACHINE ${index+1}`;}
function machineSymbols(index){const sets=[["7","$","7"],["F","7","P"],["T","*","7"],["$","$","7"],["C","7","C"],["W","7","$"]];return sets[index%sets.length];}
function machineSpace(index){const col=index%4,row=Math.floor(index/4),c=8+col*4,r=5+row*7,rect=tileRect(c,r,3,4);return {x:rect.x,y:rect.y,w:115,h:160,targetX:tileCenter(c+1,r+5).x,targetY:tileCenter(c+1,r+5).y};}
function machineSlots(){const slots=[];let owned=0;if(state.machines>0){slots.push({owned:true,old:true,name:"OLD FAITHFUL",symbols:["F","7","P"],action:"slots"});owned++;}
 if(state.brokenFixed){if(owned<state.machines){slots.push({owned:true,story:true,name:"LUCKY NUMBER THREE",symbols:["L","7","3"],action:"slots"});owned++;}}
 else slots.push({story:true,broken:true,name:"OUT OF ORDER",symbols:["!","?","R"],action:"repair"});
 while(owned<state.machines){const index=slots.length;slots.push({owned:true,name:machineLabel(index),symbols:machineSymbols(index),action:"slots"});owned++;}
 const emptyCount=Math.max(2,4-(slots.length%4||4));for(let i=0;i<emptyCount;i++)slots.push({empty:true,name:"EMPTY HOOKUP",action:"buyMachine"});
 return slots;
}
function renderMachineBank(){const bank=document.getElementById("slot-bank");if(!bank)return;const slots=machineSlots();machineSpaces.length=0;bank.innerHTML=slots.map((slot,index)=>{const space=machineSpace(index);machineSpaces.push({...space,slot});const roomOrigin=tileRect(7,3),localX=space.x-roomOrigin.x,localY=space.y-roomOrigin.y;if(slot.empty)return `<button class="machine locked empty" style="left:${localX}px;top:${localY}px" data-machine-index="${index}" data-action="buy-machine"><span>+</span><b>${slot.name}</b><small>${machineCost()} COINS</small></button>`;const needsService=state.serviceNeeded&&slot.owned&&!slot.story&&index===0;const cls=`machine ${slot.old?"old ":""}${slot.broken||needsService?"broken service ":""}`;const action=slot.broken?"repair":"slots";const sign=slot.broken?'<i class="breakdown-sign">&#128295;<em>OUT OF ORDER</em></i>':"";return `<button class="${cls.trim()}" style="left:${localX}px;top:${localY}px" data-machine-index="${index}" data-action="${action}" title="${slot.story?"Lucky Number Three":slot.name}">${sign}<span>${slot.symbols[0]}</span><span>${slot.symbols[1]}</span><span>${slot.symbols[2]}</span><b>${slot.name}</b></button>`;}).join("");
 bank.querySelectorAll("[data-action]").forEach(element=>element.addEventListener("click",event=>{event.stopPropagation();runAction(element.dataset.action);}));
 applyGridLayout();
 buildGridLayout();
 rebuildMachineTargets();
 renderFloorPlanArchitecture();
}
function rebuildMachineTargets(){if(typeof actionTargets==="undefined")return;for(let i=actionTargets.length-1;i>=0;i--)if(actionTargets[i].machine)actionTargets.splice(i,1);machineSpaces.forEach(space=>{const slot=space.slot;actionTargets.push({x:space.targetX,y:space.targetY,action:slot.action,machine:true,label:slot.empty?`Buy a slot machine (${machineCost()} coins)`:slot.broken?"Inspect Lucky Number Three":`Play ${slot.name}`});});}
function tileAtPoint(x,y){return {c:Math.floor((x-GRID.x)/GRID.t),r:Math.floor((y-GRID.y)/GRID.t)};}
function canStand(x,y,r=STAND_RADIUS,opts={}){if(!tileMap.size)buildGridLayout();return [[0,0],[r,0],[-r,0],[0,r],[0,-r],[r,r],[-r,r],[r,-r],[-r,-r]].every(([dx,dy])=>{const {c, r:row}=tileAtPoint(x+dx,y+dy);return canUseTile(tileType(c,row),opts);});}
function renderFloorPlanArchitecture(){const layer=document.getElementById("floor-plan-layer");if(!layer)return;const cells=[];tileMap.forEach((type,id)=>{const [c,r]=id.split(",").map(Number),rect=tileRect(c,r);if(type===TILE.wall)cells.push(`<i class="floor-wall" style="left:${rect.x-60}px;top:${rect.y-110}px;width:${rect.w}px;height:${rect.h}px"></i>`);else if(canUseTile(type,{allowStaff:true}))cells.push(`<i class="floor-cell ${type===TILE.door||type===TILE.exit?"door-cell":type===TILE.staff?"staff-cell":""}" style="left:${rect.x-60}px;top:${rect.y-110}px"></i>`);});layer.innerHTML=cells.join("");}
function collides(x,y){return !canStand(x,y,STAND_RADIUS,{allowStaff:true});}
function movePlayer(dx,dy,dt){if(!dx&&!dy){player.classList.remove("walking");return;}normalizePlayerPosition();const mag=Math.hypot(dx,dy)||1,step=180*dt;dx=dx/mag*step;dy=dy/mag*step;const nx=Math.max(90,Math.min(WORLD.width-90,playerPosition.x+dx));const ny=Math.max(160,Math.min(WORLD.height-70,playerPosition.y+dy));if(!collides(nx,playerPosition.y))playerPosition.x=nx;if(!collides(playerPosition.x,ny))playerPosition.y=ny;player.classList.add("walking");player.style.left=`${playerPosition.x}px`;player.style.top=`${playerPosition.y}px`;}
function updateCamera(){const vw=viewport.clientWidth,vh=viewport.clientHeight;const x=Math.min(0,Math.max(vw-WORLD.width,vw/2-playerPosition.x));const y=Math.min(0,Math.max(vh-WORLD.height,vh/2-playerPosition.y));world.style.transform=`translate3d(${Math.round(x)}px,${Math.round(y)}px,0)`;}
function nearestStandablePoint(point,opts={},standRadius=STAND_RADIUS){if(canStand(point.x,point.y,standRadius,opts))return point;for(let radius=40;radius<=900;radius+=40){for(const [dx,dy] of [[0,-radius],[radius,0],[0,radius],[-radius,0],[radius,-radius],[radius,radius],[-radius,radius],[-radius,-radius]]){const candidate={x:point.x+dx,y:point.y+dy};if(canStand(candidate.x,candidate.y,standRadius,opts))return candidate;}}return point;}
function normalizeCharacterPositions(){npcs.forEach(npc=>{const point=nearestStandablePoint({x:npc.x,y:npc.y},{allowStaff:npc.name==="Benny"},STAND_RADIUS);npc.x=point.x;npc.y=point.y;npc.el.style.left=`${npc.x}px`;npc.el.style.top=`${npc.y}px`;});}
function normalizePlayerPosition(){buildGridLayout();if(!collides(playerPosition.x,playerPosition.y))return;const from={x:Math.round(playerPosition.x),y:Math.round(playerPosition.y)};let point=nearestStandablePoint(playerPosition,{allowStaff:false},STAND_RADIUS);if(!canStand(point.x,point.y,STAND_RADIUS,{allowStaff:true}))point=nearestStandablePoint(playerPosition,{allowStaff:true},STAND_RADIUS);if(!canStand(point.x,point.y,STAND_RADIUS,{allowStaff:true}))return;playerPosition.x=point.x;playerPosition.y=point.y;player.style.left=`${playerPosition.x}px`;player.style.top=`${playerPosition.y}px`;console.log(`[movement-debug] Onyx moved from blocked tile ${from.x},${from.y} to ${Math.round(point.x)},${Math.round(point.y)}`);toast(`Movement debug: Onyx moved to ${Math.round(point.x)}, ${Math.round(point.y)}.`);saveState();}

const activitySpots={entry:tileCenter(0,12),workshopWait:tileCenter(18,18)};
const destinationPools={
 catm:[tileCenter(1,8),tileCenter(1,15)],
 cashier:[tileCenter(5,9),tileCenter(5,11),tileCenter(5,13),tileCenter(5,15)],
 slots:[tileCenter(9,9),tileCenter(13,9),tileCenter(17,9),tileCenter(21,9),tileCenter(9,16),tileCenter(13,16),tileCenter(17,16),tileCenter(21,16)],
 tables:[tileCenter(27,8),tileCenter(31,8),tileCenter(33,8),tileCenter(36,8),tileCenter(31,11)],
 tea:[tileCenter(27,18),tileCenter(29,18),tileCenter(31,18)],
 restroom:[tileCenter(34,16),tileCenter(37,16),tileCenter(36,18)],
 lounge:[tileCenter(2,19),tileCenter(5,22),tileCenter(9,19),tileCenter(12,22)],
 leaving:[tileCenter(0,12)]
};
function pickDestination(activity){const pool=destinationPools[activity]||[activitySpots.entry];return pool[Math.floor(Math.random()*pool.length)];}
function tileRoute(fromPoint,toPoint,opts={}){if(!tileMap.size)buildGridLayout();const startPoint=nearestStandablePoint(fromPoint,opts,STAND_RADIUS),endPoint=nearestStandablePoint(toPoint,opts,STAND_RADIUS),start=tileAtPoint(startPoint.x,startPoint.y),goal=tileAtPoint(endPoint.x,endPoint.y),startKey=key(start.c,start.r),goalKey=key(goal.c,goal.r),queue=[start],came=new Map([[startKey,null]]);for(let i=0;i<queue.length;i++){const current=queue[i],id=key(current.c,current.r);if(id===goalKey)break;for(const [dc,dr] of [[1,0],[-1,0],[0,1],[0,-1]]){const next={c:current.c+dc,r:current.r+dr},nextKey=key(next.c,next.r);if(came.has(nextKey)||!canUseTile(tileType(next.c,next.r),opts))continue;came.set(nextKey,id);queue.push(next);}}if(!came.has(goalKey))return [endPoint];const path=[];let cursor=goalKey;while(cursor){const [c,r]=cursor.split(",").map(Number);path.push(tileCenter(c,r));cursor=came.get(cursor);}return path.reverse().slice(1);}
function setNextRouteTarget(npc){if(npc.route?.length){const next=nearestStandablePoint(npc.route.shift(),{allowStaff:npc.name==="Benny"},STAND_RADIUS);npc.targetX=next.x;npc.targetY=next.y;}}
function scheduleVisitor(npc,now){const n=npc.needs,hour=Math.floor(state.minutes/60);if(npc.activity==="leaving"){npc.active=false;npc.el.classList.add("leaving");setTimeout(()=>{npc.el.style.display="none";npc.lifecycleAt=performance.now()+(hour>=22?36000:18000)+Math.random()*24000;},700);return;}let activity;if(npc.activity==="arriving")activity="catm";else if(n.restroom>72)activity="restroom";else if(n.thirst<35)activity="tea";else if(n.money<8)activity="cashier";else if(n.fun<30)activity=Math.random()<.65?"slots":"tables";else if(n.patience<25||n.money<3||hour>=23)activity="leaving";else if(hour<12)activity=Math.random()<.6?"tea":"lounge";else if(hour<17)activity=Math.random()<.65?"slots":"tables";else if(hour<22)activity=Math.random()<.5?"tables":"lounge";else activity=Math.random()<.5?"cashier":"leaving";npc.activity=activity;const finalSpot=pickDestination(activity),opts={allowStaff:false};npc.route=tileRoute({x:npc.x,y:npc.y},finalSpot,opts);setNextRouteTarget(npc);npc.lifecycleAt=now+6500+Math.random()*7000;npc.el.querySelector(".need-icon").textContent=activity==="tea"?"🍵":activity==="restroom"?"🚻":activity==="catm"?"🪙":activity==="leaving"?"🏠":"";if(npc.name==="Poppy"&&Math.random()<.45)npc.el.querySelector("i").textContent=npc.hats[Math.floor(Math.random()*npc.hats.length)];}
function resolveVisitorActivity(npc){const n=npc.needs;if(npc.activity==="catm"){n.money+=25;n.patience-=4;}if(npc.activity==="slots"||npc.activity==="tables"){const win=Math.random()<.4;n.fun+=win?30:12;n.money+=win?10:-5;n.happiness+=win?8:-2;}if(npc.activity==="tea"){n.thirst=100;n.happiness+=5;state.teasServed++;state.money+=2;}if(npc.activity==="restroom"){n.restroom=0;n.happiness+=state.restroomCleanliness>40?4:-10;state.restroomCleanliness=Math.max(0,state.restroomCleanliness-4);}if(npc.activity==="cashier"){n.money+=12;n.patience-=3;}if(npc.activity==="lounge"){n.patience+=20;n.happiness+=3;}n.fun=Math.max(0,n.fun-5);n.thirst=Math.max(0,n.thirst-7);n.restroom=Math.min(100,n.restroom+9);n.patience=Math.max(0,n.patience-5);n.happiness=Math.max(0,Math.min(100,n.happiness));if(Math.random()<.18)speak(npc.name,npc.lines[Math.floor(Math.random()*npc.lines.length)]);}
function updateNPC(npc,now,dt){if(npc.staff){npc.targetX=npc.home.x;npc.targetY=npc.home.y;}else{if(!npc.active){if(now<npc.lifecycleAt)return;npc.active=true;npc.el.style.display="block";npc.el.classList.remove("leaving");npc.el.classList.add("arriving");npc.x=activitySpots.entry.x;npc.y=activitySpots.entry.y;npc.activity="arriving";npc.needs={fun:55,thirst:70,restroom:10,money:25+Math.floor(Math.random()*40),happiness:78,patience:75};state.totalVisitors++;scheduleVisitor(npc,now);setTimeout(()=>npc.el.classList.remove("arriving"),1000);}else if(Math.hypot(npc.x-npc.targetX,npc.y-npc.targetY)<18){if(npc.route?.length)setNextRouteTarget(npc);else if(now>npc.lifecycleAt){resolveVisitorActivity(npc);scheduleVisitor(npc,now);}}}
 const dx=npc.targetX-npc.x,dy=npc.targetY-npc.y,d=Math.hypot(dx,dy);if(d>5){const speed=38*dt,nx=npc.x+dx/d*speed,ny=npc.y+dy/d*speed,opts={allowStaff:npc.name==="Benny"};if(canStand(nx,npc.y,STAND_RADIUS,opts))npc.x=nx;if(canStand(npc.x,ny,STAND_RADIUS,opts))npc.y=ny;npc.el.classList.add("walking");npc.el.style.left=`${npc.x}px`;npc.el.style.top=`${npc.y}px`;}else npc.el.classList.remove("walking");}

function speak(name,text){const npc=npcs.find(n=>n.name===name);if(!npc)return;const bubble=npc.el.querySelector(".speech-bubble");bubble.textContent=text;bubble.classList.add("show");setTimeout(()=>bubble.classList.remove("show"),3300);}
function talkToNPC(npc){tone(440,.09);if(npc.name==="Benny")return state.serviceNeeded?openRoutineService():openBennyWorkshop();if(npc.name==="Misty")return openMistyServices();const line=npc.lines[Math.floor(Math.random()*npc.lines.length)];speak(npc.name,line);}

const requiredParts={wires:1,springs:1,screws:2,circuitBoards:1};
const partInfo={wires:{icon:"〰️",name:"Wires"},springs:{icon:"➰",name:"Springs"},screws:{icon:"🔩",name:"Screws"},circuitBoards:{icon:"🟩",name:"Circuit Board"}};
const pickupDefs=[
 {id:"wire-floor",part:"wires",x:690,y:700},{id:"spring-floor",part:"springs",x:1260,y:790},{id:"screw-floor-a",part:"screws",x:670,y:1080},{id:"screw-floor-b",part:"screws",x:1650,y:800},{id:"board-floor",part:"circuitBoards",x:1100,y:760},
 {id:"parts-box-a",box:true,x:160,y:690},{id:"parts-box-b",box:true,x:1280,y:1080}
];
const actionTargets=[{x:1240,y:530,action:"blackjack",label:"Play Blackjack"},{x:1480,y:530,action:"roulette",label:"Play Roulette"},{x:1320,y:970,action:"tea",label:"Order Catnip Tea"},{x:180,y:630,action:"catm",label:"Use CATM"},{x:180,y:870,action:"catm",label:"Use CATM"},{x:1540,y:930,action:"restroom",label:"Clean Powder Paw Room"}];
function createPickups(){const layer=document.getElementById("pickup-layer");pickupDefs.forEach(item=>{const el=document.createElement("div");el.className=`pickup ${item.box?"parts-box":""}`;el.dataset.pickup=item.id;el.style.left=`${item.x}px`;el.style.top=`${item.y}px`;el.innerHTML=item.box?`<i>📦</i><b>PARTS BOX</b>`:`<i>${partInfo[item.part].icon}</i><b>${partInfo[item.part].name.toUpperCase()}</b>`;layer.appendChild(el);item.el=el;actionTargets.push({x:item.x+20,y:item.y+20,pickup:item,label:item.box?"Search parts box":`Pick up ${partInfo[item.part].name}`});});refreshPickups();}
function refreshPickups(){pickupDefs.forEach(item=>{if(!item.el)return;const unavailable=state.repairStage==="not_started"||state.repairStage==="complete"||state.foundParts.includes(item.id);item.el.classList.toggle("collected",unavailable);});}
function collectPickup(item){if(state.repairStage==="not_started")return toast("Benny might know what these are for.");if(state.foundParts.includes(item.id))return;let part=item.part;if(item.box){const missing=Object.keys(requiredParts).filter(key=>state.parts[key]<requiredParts[key]);part=missing.length?missing[Math.floor(Math.random()*missing.length)]:Object.keys(requiredParts)[Math.floor(Math.random()*4)];}state.parts[part]++;state.foundParts.push(item.id);item.el.classList.add("collected");toast(`Found ${partInfo[part].name}!`);tone(620,.18);updateRepairObjective();updateHUD();}
createPickups();
function findNearby(){let best=null,distance=75;actionTargets.forEach(target=>{if(target.pickup&&(state.repairStage==="not_started"||state.repairStage==="complete"||state.foundParts.includes(target.pickup.id)))return;const d=Math.hypot(playerPosition.x-target.x,playerPosition.y-target.y);if(d<distance){best=target;distance=d;}});npcs.forEach(npc=>{const d=Math.hypot(playerPosition.x-npc.x,playerPosition.y-npc.y);if(d<distance){best={npc,label:`Talk to ${npc.name}`};distance=d;}});if(vinnyVisible){const vinny=document.getElementById("vinny"),x=parseFloat(vinny.style.left),y=parseFloat(vinny.style.top),d=Math.hypot(playerPosition.x-x,playerPosition.y-y);if(d<distance)best={action:"vinny",label:"Talk to Vinny"};}nearbyTarget=best;prompt.classList.toggle("hidden",!best);if(best)prompt.querySelector("span").textContent=best.label;}

function runAction(action){const actions={slots:openSlots,repair:inspectBrokenMachine,buyMachine:buyMachine,"buy-machine":buyMachine,blackjack:()=>openMiniGame("Blackjack",10,22),roulette:()=>openMiniGame("Roulette",10,30),tea:buyTea,catm:openCATM,restroom:cleanRestroom,vinny:talkVinny};actions[action]?.();}
function interact(){if(!nearbyTarget)return;if(nearbyTarget.npc)return talkToNPC(nearbyTarget.npc);if(nearbyTarget.pickup)return collectPickup(nearbyTarget.pickup);runAction(nearbyTarget.action);}
function showDialog(html){const dialog=document.getElementById("dialog");document.getElementById("dialog-body").innerHTML=html;if(!dialog.open)dialog.showModal();}
document.querySelector(".dialog-close").onclick=()=>document.getElementById("dialog").close();
document.querySelectorAll("[data-action]").forEach(element=>element.addEventListener("click",event=>{event.stopPropagation();runAction(element.dataset.action);}));

function openSlots(){showDialog(`<div class="dialog-scene"><p class="chapter">Lucky Paw Slots</p><h2>Old Faithful</h2><div class="reels"><span id="r1">🐟</span><span id="r2">7</span><span id="r3">🐾</span></div><p id="game-result">Three matching symbols win 60 coins. Two win 15.</p><button id="spin-game">SPIN — 5 COINS</button></div>`);document.getElementById("spin-game").onclick=spinSlots;}
function spinSlots(){if(state.money<5)return document.getElementById("game-result").textContent="Not enough Catnip Coins.";ensureAudio();state.spins++;state.loyaltyPoints++;state.money-=5;const symbols=["🐟","7","🐾","🧶","🐱"],result=[];[1,2,3].forEach((n,i)=>{result.push(symbols[Math.floor(Math.random()*symbols.length)]);document.getElementById(`r${n}`).textContent=result[i];tone(250+i*80,.12,"square");});if(new Set(result).size===1){state.money+=60;state.reputation+=2;state.jackpots++;document.getElementById("game-result").textContent="JACKPOT! +60 coins!";jackpot();}else if(new Set(result).size===2){state.money+=15;document.getElementById("game-result").textContent="A tidy little win! +15 coins.";}else document.getElementById("game-result").textContent="Not this time. Old Faithful coughs politely.";updateHUD();}
function jackpot(){npcs.forEach(npc=>speak(npc.name,npc.name==="Sir Midnight"?"...Nice.":"JACKPOT!"));for(let i=0;i<24;i++){const p=document.createElement("i");p.className="particle";p.style.left=`${playerPosition.x+(Math.random()-.5)*300}px`;p.style.top=`${playerPosition.y+(Math.random()-.5)*140}px`;document.getElementById("world-effects").appendChild(p);setTimeout(()=>p.remove(),1300);}tone(880,.4,"triangle",.15);}
function hasAllParts(){return Object.keys(requiredParts).every(part=>state.parts[part]>=requiredParts[part]);}
function updateRepairObjective(){if(state.serviceNeeded)return document.getElementById("quest-text").textContent="Ask Benny to service the sparking machine";if(state.repairStage==="not_started")document.getElementById("quest-text").textContent="Talk to Benny about the broken machine";else if(state.repairStage==="gathering"){const missing=Object.keys(requiredParts).filter(part=>state.parts[part]<requiredParts[part]);document.getElementById("quest-text").textContent=missing.length?`Gather repair parts (${Object.keys(requiredParts).length-missing.length}/${Object.keys(requiredParts).length} types ready)`:"Return to Benny with the repair parts";}else if(state.repairStage==="repairing")document.getElementById("quest-text").textContent="Help Benny repair the machine";else document.getElementById("quest-text").textContent="Earn 200 Catnip Coins for the first expansion";}
function beginRepairQuest(){state.repairStage="gathering";state.quest=1;document.getElementById("dialog").close();refreshPickups();updateRepairObjective();updateHUD();toast("Repair quest started — parts are scattered around the casino.");setTimeout(()=>speak("Poppy","New machine smell? No, that's burned wires."),900);}
function openBennyWorkshop(){if(state.repairStage==="complete")return showDialog(`<div class="dialog-scene"><div class="portrait">🐈‍⬛🧢</div><h2>Benny's Workshop</h2><p>“Nothing's exploded. Weird.”</p><div class="story-note">Last serviced: ${state.lastServiced}</div></div>`);if(state.repairStage==="not_started"){showDialog(`<div class="dialog-scene"><div class="portrait">🐈‍⬛🧢</div><h2>Benny</h2><p>“Uncle Whiskers always said machines are just puzzles with bad attitudes.”</p><p>Old Lucky Number Three needs wires, a spring, two screws, and a circuit board. Some parts are lying around; check the old boxes too.</p><button id="accept-repair">HELP BENNY REPAIR IT</button></div>`);document.getElementById("accept-repair").onclick=beginRepairQuest;return;}const ready=hasAllParts();showDialog(`<div class="dialog-scene"><div class="portrait">🐈‍⬛🧢</div><h2>Benny's Workshop</h2><p>“${ready?"Hit it with a wrench first. That's science.":"Nothing's exploded today. Weird."}”</p>${partsChecklist()}<p>Short on something? Benny keeps questionably organized spares.</p><div class="benny-shop">${Object.keys(requiredParts).map(part=>`<button data-buy-part="${part}">Buy ${partInfo[part].name} — ${part==="circuitBoards"?8:4}🪙</button>`).join("")}</div>${ready?'<button id="start-repair">REPAIR THE MACHINE</button>':''}</div>`);document.querySelectorAll("[data-buy-part]").forEach(button=>button.onclick=()=>buyPart(button.dataset.buyPart));if(ready)document.getElementById("start-repair").onclick=startRepairAnimation;}
function buyPart(part){const cost=part==="circuitBoards"?8:4;if(state.money<cost)return toast("Not enough Catnip Coins.");state.money-=cost;state.parts[part]++;updateRepairObjective();updateHUD();state.serviceNeeded?openRoutineService():openBennyWorkshop();}
function partsChecklist(){return `<div class="journal-parts">${Object.keys(requiredParts).map(part=>{const have=state.parts[part],need=requiredParts[part];return `<div class="journal-part ${have>=need?'have':''}">${partInfo[part].icon} ${partInfo[part].name}<br><b>${have}/${need}</b></div>`;}).join("")}</div>`;}
function inspectBrokenMachine(){if(state.repairStage==="not_started")return toast("OUT OF ORDER — Benny will know what it needs.");if(state.repairStage==="complete")return openSlots();showMaintenanceJournal();}
function startRepairAnimation(){if(!hasAllParts())return toast("The repair kit is still missing parts.");ensureAudio();state.repairStage="repairing";updateRepairObjective();showDialog(`<div class="dialog-scene"><p class="chapter">Maintenance Team-Up</p><h2>Onyx & Benny at Work</h2><div class="repair-stage"><div class="repair-cats">🐈‍⬛　🐈‍⬛</div><div class="repair-wrench">🔧</div><div class="repair-sparks">✦ ⚡ ✦</div><div class="progress-track"><div class="progress-fill" id="repair-progress"></div></div></div><p id="repair-status">Benny is considering which wrench looks smartest...</p></div>`);document.querySelector(".dialog-close").disabled=true;let progress=0;const messages=["Removing a suspicious amount of lint...","Onyx holds the flashlight perfectly...","Benny applies calibrated percussive maintenance...","Reconnecting the last wire..."];const timer=setInterval(()=>{progress+=10;document.getElementById("repair-progress").style.width=`${progress}%`;document.getElementById("repair-status").textContent=messages[Math.min(messages.length-1,Math.floor(progress/30))];tone(progress%20?430:180,.08,progress%20?"square":"sawtooth");spawnRepairSparks();if(progress>=100){clearInterval(timer);setTimeout(finishRepair,350);}},280);}
function spawnRepairSparks(){for(let i=0;i<3;i++){const spark=document.createElement("i");spark.className="particle";spark.style.left=`${470+Math.random()*80}px`;spark.style.top=`${390+Math.random()*60}px`;document.getElementById("world-effects").appendChild(spark);setTimeout(()=>spark.remove(),1200);}}
function finishRepair(){Object.keys(requiredParts).forEach(part=>state.parts[part]-=requiredParts[part]);state.brokenFixed=true;state.repairStage="complete";state.quest=2;state.machines++;state.reputation+=8;state.lastServiced=`Lucky Number Three — Day ${state.day}`;const machine=document.querySelector(".machine.broken");if(machine){machine.classList.remove("broken");machine.querySelector(".breakdown-sign")?.remove();machine.querySelector("b").textContent="BENNY'S BEST";}document.querySelector(".dialog-close").disabled=false;showDialog(`<div class="dialog-scene"><div class="portrait">🎰✨</div><h2>Back in Business!</h2><p>Lucky Number Three hums to life and begins earning Catnip Coins.</p><div class="story-note">Benny: “Only two screws left over. That's basically a record.”</div></div>`);refreshPickups();updateRepairObjective();updateHUD();tone(880,.45,"triangle",.16);speak("Poppy","New machine smell? No, that's burned wires.");setTimeout(()=>speak("Sir Midnight","I preferred it broken. It gave the room character."),1800);}
function showMaintenanceJournal(){const status=state.repairStage==="complete"?"Operational":state.repairStage==="repairing"?"Repair in progress":"Out of Order";showDialog(`<div class="journal-list"><p class="chapter">Maintenance Journal</p><h2>🔧 Uncle Whiskers' Service Log</h2><div class="journal-row ${state.brokenFixed?'done':''}"><div><b>Lucky Number Three</b><small> Slot Machine • West Floor</small></div><strong>${status}</strong></div>${partsChecklist()}<div class="journal-row"><span>Repair progress</span><b>${state.repairStage==="complete"?'100%':hasAllParts()?'Parts ready':state.repairStage==="not_started"?'Not diagnosed':'Gathering parts'}</b></div><div class="story-note">Last machine serviced: ${state.lastServiced}</div></div>`);}
document.getElementById("journal-button").onclick=showMaintenanceJournal;
function openMiniGame(name,cost,prize){showDialog(`<div class="dialog-scene"><div class="portrait">${name==="Blackjack"?"🃏":"🎡"}</div><h2>${name}</h2><p id="game-result">A round costs ${cost} coins. Win ${prize}.</p><button id="play-mini">PLAY</button></div>`);document.getElementById("play-mini").onclick=()=>{if(state.money<cost)return document.getElementById("game-result").textContent="Not enough coins.";state.money-=cost;const win=Math.random()<.43;if(win){state.money+=prize;document.getElementById("game-result").textContent=`A classy win! +${prize} coins.`;tone(660,.2);}else document.getElementById("game-result").textContent="The house wins. It tries not to look smug.";updateHUD();};}
function buyTea(){if(state.money<3)return toast("Even tea requires three coins.");state.money-=3;state.teasServed++;state.visitorHappiness=Math.min(100,state.visitorHappiness+1);toast("Minty Meow Tea: movement feels extra smooth. 🍵");tone(520,.18);updateHUD();}
function machineCost(){return 50+Math.max(0,state.machines-1)*25;}
function buyMachine(){const cost=machineCost();if(state.money<cost)return toast(`A new machine costs ${cost} Catnip Coins.`);state.money-=cost;state.machines++;state.machineCondition=Math.min(100,state.machineCondition+10);state.reputation+=1;toast(`New slot machine installed! Income increased. Next: ${machineCost()} coins.`);tone(620,.18);updateHUD();}
document.getElementById("buy-machine-button").onclick=buyMachine;
function openCATM(){showDialog(`<div class="dialog-scene"><div class="portrait">🏧🐾</div><h2>CATM</h2><p>Catnip Automated Teller Machine</p><div class="service-grid"><button id="catm-withdraw">Withdraw 20 coins</button><button id="catm-emergency">Emergency coin recovery</button></div><p class="visitor-detail">Visitors use CATMs before playing so they don't wander forever with empty pockets.</p></div>`);document.getElementById("catm-withdraw").onclick=()=>{state.money+=20;state.loyaltyPoints++;toast("Withdrew 20 Catnip Coins.");updateHUD();};document.getElementById("catm-emergency").onclick=()=>{if(state.money>0)return toast("Emergency coins are only for totally empty pockets.");if(state.emergencyDay===state.day)return toast("Emergency recovery already used today.");state.money=15;state.emergencyDay=state.day;toast("CATM issued 15 emergency coins. Uncle would approve.");updateHUD();};}
function openMistyServices(){showDialog(`<div class="dialog-scene"><div class="portrait">🐱🎀</div><h2>Misty's Counter</h2><p>“I don't gossip. I curate information.”</p><div class="service-grid"><button id="daily-reward">Daily reward</button><button id="loyalty-reward">Loyalty reward</button><button id="lost-found">Lost & found</button><button id="mail-button">Mail</button><button id="emergency-misty">Emergency coins</button><button id="cash-bonus">Cash out bonus</button></div></div>`);document.getElementById("daily-reward").onclick=()=>{if(state.lastDaily===state.day)return toast("Misty says you already got today's reward.");state.money+=25;state.lastDaily=state.day;toast("Daily reward: +25 coins.");updateHUD();};document.getElementById("loyalty-reward").onclick=()=>{if(state.loyaltyPoints<3)return toast("Earn 3 loyalty points from CATMs and games first.");state.loyaltyPoints-=3;state.money+=35;toast("Loyalty reward: +35 coins.");updateHUD();};document.getElementById("lost-found").onclick=()=>{if(state.lostFoundDay===state.day)return toast("Lost and found is empty today.");state.lostFoundDay=state.day;state.parts.screws++;toast("Found a screw in a velvet coin pouch.");updateHUD();};document.getElementById("mail-button").onclick=()=>{if(state.mailClaimedDay===state.day)return toast("No more mail today.");state.mailClaimedDay=state.day;state.reputation+=1;toast("Fan mail from a kitten: +1 reputation.");updateHUD();};document.getElementById("emergency-misty").onclick=()=>{if(state.money>0)return toast("Misty only opens the emergency tin when you're broke.");state.money=20;toast("Misty slides over 20 coins and pretends not to care.");updateHUD();};document.getElementById("cash-bonus").onclick=()=>{if(state.money<100)return toast("Cash out bonus starts at 100 coins.");state.money+=10;state.cashOuts++;toast("Responsible cash-out bonus: +10 coins.");updateHUD();};}
function cleanRestroom(){state.restroomCleanliness=100;state.reputation+=1;toast("The Powder Paw Room sparkles. Customers appreciate it.");tone(540,.2);updateHUD();}
function openRoutineService(){const ready=state.parts.wires>=1&&state.parts.screws>=1;showDialog(`<div class="dialog-scene"><div class="portrait">🐈‍⬛🧢</div><h2>Benny's Service Call</h2><p>“Hit it with a wrench first. That's science.”</p><p>Routine repair needs 1 wire and 1 screw.</p><div class="journal-parts"><div class="journal-part ${state.parts.wires>=1?'have':''}">〰️ Wires<br><b>${state.parts.wires}/1</b></div><div class="journal-part ${state.parts.screws>=1?'have':''}">🔩 Screws<br><b>${state.parts.screws}/1</b></div></div><div class="benny-shop"><button data-buy-part="wires">Buy Wires — 4🪙</button><button data-buy-part="screws">Buy Screws — 4🪙</button></div>${ready?'<button id="routine-service">SERVICE MACHINE</button>':''}</div>`);document.querySelectorAll("[data-buy-part]").forEach(button=>button.onclick=()=>buyPart(button.dataset.buyPart));if(ready)document.getElementById("routine-service").onclick=()=>{state.parts.wires--;state.parts.screws--;state.serviceNeeded=false;state.machineCondition=100;state.lastServiced=`Routine service — Day ${state.day}`;document.querySelector(".machine.broken")?.classList.remove("broken");toast("Benny services the machine. It stops making goblin noises.");tone(700,.25);updateRepairObjective();updateHUD();document.getElementById("dialog").close();};}

const achievementDefs=[
 ["First Spin","Take your first spin",()=>state.spins>=1],["First Jackpot","Hit any jackpot",()=>state.jackpots>=1],["Repair First Machine","Bring Lucky Number Three back",()=>state.brokenFixed],["Meet Vinny","Talk to Vinny",()=>state.vinnyMet],["Meet Uncle Whiskers' Ghost","See Uncle Whiskers after 10 PM",()=>state.ghostMet],["Own 10 Machines","Build a respectable slot row",()=>state.machines>=10],["Own 25 Machines","Become a machine mogul",()=>state.machines>=25],["Reach 100 Reputation","Become the talk of the town",()=>state.reputation>=100],["Serve 100 Teas","Keep the casino cozy",()=>state.teasServed>=100],["Become Local Legend","Reach 150 reputation and full resort dreams",()=>state.reputation>=150]
];
function updateAchievements(){let changed=false;achievementDefs.forEach(([name,,test])=>{if(test()&&!state.achievements.includes(name)){state.achievements.push(name);changed=true;}});return changed;}
function showAchievements(){updateAchievements();showDialog(`<div class="dialog-scene"><p class="chapter">Separate from Blueprints</p><h2>Achievements</h2><div class="achievement-grid">${achievementDefs.map(([name,desc])=>`<div class="achievement-card ${state.achievements.includes(name)?'unlocked':''}">${state.achievements.includes(name)?'🏆':'🔒'} <b>${name}</b><br><small>${desc}</small></div>`).join("")}</div></div>`);}
document.getElementById("achievements-button").onclick=showAchievements;

const expansions=[{name:"Better Slot Machines",cost:250,rep:55,machines:10},{name:"Tea Bar",cost:350,rep:65,machines:12},{name:"Arcade",cost:550,rep:75,machines:14},{name:"Aquarium",cost:750,rep:85,machines:16},{name:"VIP Lounge",cost:950,rep:95,machines:18},{name:"Pool",cost:1200,rep:105,machines:20},{name:"Hotel Tower",cost:1500,rep:120,machines:22},{name:"Penthouse",cost:1900,rep:140,machines:25},{name:"Parking Garage",cost:2300,rep:155,machines:28},{name:"Full Resort",cost:3000,rep:175,machines:30}];
function renderExpansions(){document.getElementById("expansion-list").innerHTML=expansions.map((item,i)=>{const owned=state.expansions.includes(item.name),locked=state.reputation<item.rep||state.machines<item.machines;return `<article class="expansion-item ${owned?'unlocked':''}"><b>${owned?'✓ ':locked?'🔒 ':''}${i+1}. ${item.name}</b><small>${owned?'Built and bustling':locked?`Requires ${item.rep} reputation and ${item.machines} machines`:`Renovation milestone • ${item.cost} coins`}</small><button data-build="${i}" ${owned||locked?'disabled':''}>${owned?'BUILT':`BUILD — ${item.cost}`}</button></article>`;}).join("");document.querySelectorAll("[data-build]").forEach(button=>button.onclick=()=>buildExpansion(+button.dataset.build));}
function buildExpansion(index){const item=expansions[index];if(state.money<item.cost)return toast(`You need ${item.cost} coins.`);state.money-=item.cost;state.reputation+=8;state.expansions.push(item.name);toast(`${item.name} is now open!`);renderExpansions();updateHUD();}
document.getElementById("expansion-button").onclick=()=>{renderExpansions();document.getElementById("expansion-panel").classList.add("open");};document.querySelector(".panel-close").onclick=()=>document.getElementById("expansion-panel").classList.remove("open");

function showVinny(){const el=document.getElementById("vinny");el.classList.remove("hidden");el.style.left="1240px";el.style.top="770px";vinnyVisible=true;setTimeout(()=>{if(vinnyVisible){el.classList.add("hidden");vinnyVisible=false;}},22000);}
function talkVinny(){state.vinnyMet=true;const lines=["These coins? Completely legitimate. Mostly.","Never trust a dealer with cleaner paws than you.","I know a guy. I am the guy."];const line=lines[Math.floor(Math.random()*lines.length)];showDialog(`<div class="dialog-scene"><div class="portrait">🦝🎩</div><h2>Vinny</h2><p>“${line}”</p><p>Give Vinny 15 coins for a mystery deal?</p><button id="vinny-deal">MAKE THE DEAL</button></div>`);document.getElementById("vinny-deal").onclick=()=>{if(state.money<15)return toast("Vinny sighs. 'Come back with the lettuce.'");state.money-=15;if(state.repairStage==="gathering"&&Math.random()<.45){const missing=Object.keys(requiredParts).filter(part=>state.parts[part]<requiredParts[part]);const part=missing.length?missing[Math.floor(Math.random()*missing.length)]:"screws";state.parts[part]++;toast(`Vinny's envelope contained ${partInfo[part].name}. Don't ask.`);updateRepairObjective();}else{const reward=Math.random()<.7?30:5;state.money+=reward;toast(`Vinny's envelope contained ${reward} coins.`);}document.getElementById("vinny-deal").disabled=true;updateHUD();};}
setTimeout(showVinny,18000+Math.random()*18000);setInterval(()=>{if(!vinnyVisible&&Math.random()<.45)showVinny();},45000);

document.addEventListener("keydown",event=>{if(["ArrowUp","ArrowDown","ArrowLeft","ArrowRight","w","a","s","d","W","A","S","D"].includes(event.key))event.preventDefault();keys.add(event.key.toLowerCase());if(event.key.toLowerCase()==="e"||event.key==="Enter")interact();});document.addEventListener("keyup",event=>keys.delete(event.key.toLowerCase()));
prompt.addEventListener("pointerdown",interact);

const weatherTypes=["Sunny","Drizzle","Rain","Thunderstorm","Snow"],weatherIcons={Sunny:"☀️",Drizzle:"🌦️",Rain:"🌧️",Thunderstorm:"⛈️",Snow:"❄️"},seasons=["Spring","Summer","Autumn","Winter"],seasonIcons={Spring:"🌸",Summer:"☀️",Autumn:"🍂",Winter:"❄️"};
function currentSeason(){return seasons[Math.floor((state.day-1)/14)%seasons.length];}
function chooseWeather(){const season=currentSeason(),pool=season==="Winter"?["Snow","Snow","Sunny","Rain"]:season==="Summer"?["Sunny","Sunny","Drizzle","Thunderstorm"]:["Sunny","Drizzle","Rain","Thunderstorm"];state.weather=pool[Math.floor(Math.random()*pool.length)];state.weatherDaysLeft=2+Math.floor(Math.random()*4);applyWeather();}
function applyWeather(){document.getElementById("weather-label").textContent=`${weatherIcons[state.weather]} ${state.weather}`;document.getElementById("season-chip").textContent=`${seasonIcons[currentSeason()]} ${currentSeason()}`;let layer=document.querySelector(".weather-particles");if(!layer){layer=document.createElement("div");layer.className="weather-particles";document.querySelector(".outside-strip").appendChild(layer);}layer.innerHTML="";if(state.weather==="Snow")for(let i=0;i<35;i++){const flake=document.createElement("i");flake.className="snowflake";flake.textContent="❄";flake.style.left=`${Math.random()*100}%`;flake.style.top=`${-Math.random()*800}px`;flake.style.animationDelay=`${Math.random()*6}s`;layer.appendChild(flake);}if(state.weather==="Thunderstorm"){const flash=document.createElement("i");flash.className="thunder-flash";layer.appendChild(flash);}}
function newGameDay(){state.weatherDaysLeft--;if(state.weatherDaysLeft<=0)chooseWeather();state.restroomCleanliness=Math.max(0,state.restroomCleanliness-2);state.seasonDay=(state.seasonDay||1)+1;updateHUD();}
function weatherComment(){if(state.weather==="Rain"||state.weather==="Drizzle")return Math.random()<.5?["Bianca","Darling, rainy days are excellent for tea."]:["Marmalade","I refuse to get my paws wet."];if(state.weather==="Snow")return ["Poppy","Snow is just confetti with boundaries."];if(state.weather==="Thunderstorm")return ["Misty","That thunder was not one of Benny's machines. Probably."];return ["Bianca","Finally, weather worthy of my sunglasses."];}
setInterval(()=>{if(!gameStarted)return;if(Math.random()<.28){const [name,line]=weatherComment();speak(name,line);}if(state.weather==="Thunderstorm"&&Math.random()<.35){const flash=document.querySelector(".thunder-flash");if(flash){flash.classList.remove("flash");void flash.offsetWidth;flash.classList.add("flash");tone(70,.5,"sawtooth",.05);}}},14000);

let ghostAccumulator=0,ghostPresent=false;
const ghostSpots=[{x:1090,y:555,type:"roulette"},{x:1450,y:690,type:"tea bar"},{x:345,y:930,type:"favorite chair"}];
function updateGhost(dt){const hour=Math.floor(state.minutes/60);if(hour<22&&hour>=6)return;ghostAccumulator+=dt;if(ghostAccumulator<18||ghostPresent)return;ghostAccumulator=0;if(Math.random()>.42)return;state.ghostMet=true;const ghost=document.getElementById("uncle-ghost"),spot=ghostSpots[Math.floor(Math.random()*ghostSpots.length)];ghost.style.left=`${spot.x}px`;ghost.style.top=`${spot.y}px`;ghost.classList.remove("hidden");ghostPresent=true;const messages=["You feel like Uncle Whiskers is proud of you.","Someone left fresh catnip tea on the table. Strange...","For a moment, you could swear you heard him laugh."];setTimeout(()=>toast(messages[Math.floor(Math.random()*messages.length)]),1200);if(Math.random()<.3){setTimeout(()=>speak("Misty","Did anybody else see that?"),1700);setTimeout(()=>speak("Bianca","Oh darling, that's just Uncle Whiskers checking on us."),3200);}setTimeout(()=>{if(spot.type==="roulette"&&Math.random()<.5){toast("The roulette ball lands on Uncle Whiskers' old number. The chair is suddenly empty.");tone(720,.35,"triangle");}ghost.classList.add("hidden");ghostPresent=false;},11000);}
function updateClock(dt){const beforeDay=state.day;state.minutes+=dt/12;if(state.minutes>=1440){state.minutes-=1440;state.day++;newGameDay();}const hours=Math.floor(state.minutes/60),mins=Math.floor(state.minutes%60),displayHour=hours%12||12,period=hours<12?"AM":"PM";document.getElementById("game-time").textContent=`${displayHour}:${String(mins).padStart(2,"0")} ${period}`;document.getElementById("day-label").textContent=`DAY ${state.day}`;const night=hours>=19||hours<6;document.getElementById("day-night").style.opacity=night?".46":hours>=17?".2":"0";if(beforeDay!==state.day)saveState();}
function updateWorldSystems(dt){const visitors=npcs.filter(n=>!n.staff&&n.active);document.getElementById("visitor-count").textContent=visitors.length;const avg=visitors.length?visitors.reduce((sum,n)=>sum+n.needs.happiness,0)/visitors.length:82;state.visitorHappiness=Math.max(0,Math.min(100,(state.visitorHappiness*.98)+(avg*.02)));if(state.restroomCleanliness<35)state.visitorHappiness=Math.max(0,state.visitorHappiness-dt*.4);if(state.brokenFixed&&!state.serviceNeeded){state.machineCondition-=dt*(0.012+state.machines*.001);if(state.machineCondition<=0){state.serviceNeeded=true;state.machineCondition=0;state.reputation=Math.max(0,state.reputation-3);toast("A slot machine starts coughing sparks. Benny is already frowning.");speak("Benny","Machines are just puzzles with bad attitudes.");document.querySelector('.machine:not(.locked)')?.classList.add("broken");updateRepairObjective();}}}
let incomeAccumulator=0,systemsAccumulator=0;function gameLoop(now){const dt=Math.min((now-lastFrame)/1000,.05);lastFrame=now;if(!gameStarted){updateCamera();requestAnimationFrame(gameLoop);return;}let dx=0,dy=0;if(keys.has("a")||keys.has("arrowleft"))dx-=1;if(keys.has("d")||keys.has("arrowright"))dx+=1;if(keys.has("w")||keys.has("arrowup"))dy-=1;if(keys.has("s")||keys.has("arrowdown"))dy+=1;movePlayer(dx,dy,dt);updateCamera();npcs.forEach(npc=>updateNPC(npc,now,dt));findNearby();updateClock(dt);updateGhost(dt);systemsAccumulator+=dt;if(systemsAccumulator>1){systemsAccumulator=0;updateWorldSystems(1);}incomeAccumulator+=dt;if(incomeAccumulator>12){incomeAccumulator=0;const income=Math.max(1,state.machines-(state.serviceNeeded?1:0));state.money+=income;if(state.restroomCleanliness>70&&state.visitorHappiness>80)state.reputation+=.05;updateHUD();const coin=document.createElement("span");coin.className="coin-pop";coin.textContent=`+${income}🪙`;coin.style.left="330px";coin.style.top="320px";document.getElementById("world-effects").appendChild(coin);setTimeout(()=>coin.remove(),1400);}requestAnimationFrame(gameLoop);}
function applySavedRepairState(){if(!state.brokenFixed)return;const machine=document.querySelector(".machine.broken");if(machine){if(state.serviceNeeded){machine.querySelector("b").textContent="SERVICE NEEDED";}else{machine.classList.remove("broken");machine.querySelector(".breakdown-sign")?.remove();machine.querySelector("b").textContent="BENNY'S BEST";}}refreshPickups();}
applyWeather();updateRepairObjective();updateHUD();applySavedRepairState();normalizeCharacterPositions();normalizePlayerPosition();player.style.left=`${playerPosition.x}px`;player.style.top=`${playerPosition.y}px`;updateCamera();requestAnimationFrame(gameLoop);setInterval(saveState,5000);window.addEventListener("beforeunload",saveState);
